create extension if not exists pgcrypto;
create table if not exists public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text,full_name text,role text check(role in('admin','student')) default 'student',created_at timestamptz default now());
create table if not exists public.batches(id uuid primary key default gen_random_uuid(),name text not null,course text not null,class_level text not null,created_at timestamptz default now());
create table if not exists public.students(id uuid primary key default gen_random_uuid(),user_id uuid unique references auth.users(id) on delete cascade,student_id text unique not null,auth_email text unique not null,full_name text not null,course text not null,class_level text not null,batch_id uuid references public.batches(id) on delete set null,phone text,created_at timestamptz default now());
create sequence if not exists public.student_number_seq start 1001;
create or replace function public.next_student_id() returns text language sql security definer as $$select 'APEX'||nextval('public.student_number_seq')::text$$;
create table if not exists public.fees(id uuid primary key default gen_random_uuid(),student_user_id uuid references auth.users(id) on delete cascade,student_id text,amount numeric not null,month text,status text default 'due',created_at timestamptz default now());
create table if not exists public.notes(id uuid primary key default gen_random_uuid(),title text not null,subject text,course text,class_level text,batch_id uuid,file_path text not null,file_name text,published boolean default true,created_by uuid,created_at timestamptz default now());
create table if not exists public.doubts(id uuid primary key default gen_random_uuid(),student_user_id uuid references auth.users(id) on delete cascade,student_id text,subject text,question text not null,answer text,status text default 'pending',answered_by uuid,answered_at timestamptz,created_at timestamptz default now());
create table if not exists public.notifications(id uuid primary key default gen_random_uuid(),title text not null,message text not null,audience text default 'all',created_by uuid,created_at timestamptz default now());
create or replace function public.handle_new_user() returns trigger language plpgsql security definer as $$begin insert into public.profiles(id,email,full_name,role) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'full_name',''),coalesce(new.raw_user_meta_data->>'role','student')) on conflict(id) do nothing;return new;end$$;
drop trigger if exists on_auth_user_created on auth.users;create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
create or replace function public.is_admin() returns boolean language sql stable security definer as $$select exists(select 1 from public.profiles where id=auth.uid() and role='admin')$$;
alter table public.profiles enable row level security;alter table public.students enable row level security;alter table public.batches enable row level security;alter table public.fees enable row level security;alter table public.notes enable row level security;alter table public.doubts enable row level security;alter table public.notifications enable row level security;
create policy "profiles own or admin" on public.profiles for select using(id=auth.uid() or public.is_admin());
create policy "students own or admin" on public.students for select using(user_id=auth.uid() or public.is_admin());
create policy "admin students" on public.students for all using(public.is_admin()) with check(public.is_admin());
create policy "batches authenticated read" on public.batches for select using(auth.uid() is not null);create policy "admin batches" on public.batches for all using(public.is_admin()) with check(public.is_admin());
create policy "fees own or admin" on public.fees for select using(student_user_id=auth.uid() or public.is_admin());create policy "admin fees" on public.fees for all using(public.is_admin()) with check(public.is_admin());
create policy "notes authenticated read" on public.notes for select using(auth.uid() is not null and published=true);create policy "admin notes" on public.notes for all using(public.is_admin()) with check(public.is_admin());
create policy "doubts own or admin" on public.doubts for select using(student_user_id=auth.uid() or public.is_admin());create policy "student creates doubt" on public.doubts for insert with check(student_user_id=auth.uid());create policy "admin updates doubts" on public.doubts for update using(public.is_admin());
create policy "notifications authenticated read" on public.notifications for select using(auth.uid() is not null);create policy "admin notifications" on public.notifications for all using(public.is_admin()) with check(public.is_admin());
insert into storage.buckets(id,name,public) values('apex-chemistry-files','apex-chemistry-files',false) on conflict(id) do update set public=false;
create policy "authenticated note downloads" on storage.objects for select using(bucket_id='apex-chemistry-files' and auth.uid() is not null);create policy "admin note uploads" on storage.objects for insert with check(bucket_id='apex-chemistry-files' and public.is_admin());create policy "admin note changes" on storage.objects for all using(bucket_id='apex-chemistry-files' and public.is_admin());
